@function colorLuminance($color)
  $color-rgb: ('red': red($color),'green': green($color),'blue': blue($color))
  @each $name, $value in $color-rgb
    $adjusted: 0
    $value: $value / 255
    @if $value < 0.03928
      $value: $value / 12.92
    @else
      $value: ($value + .055) / 1.055
      $value: powerNumber($value, 2)
    $color-rgb: map-merge($color-rgb, ($name: $value))
  @return (map-get($color-rgb, 'red') * .2126) + (map-get($color-rgb, 'green') * .7152) + (map-get($color-rgb, 'blue') * .0722)

@function luminance($color)

	@if meta.type-of($color) != 'color'
		@error parameter-type.parameter-type('luminance', 'color', $color, 'color')

	$color: color.red($color), color.green($color), color.blue($color)

	@for $i from 1 through 3
		$channel: math.div(list.nth($color, $i), 255)
		$channel: if($channel <= 0.03928, math.div($channel, 12.92), math.pow(math.div($channel + 0.055, 1.055), 2.4))
		$color: list.set-nth($color, $i, $channel)

	@return 0.2126 * list.nth($color, 1) + 0.7152 * list.nth($color, 2) + 0.0722 * list.nth($color, 3)

=box-shadow($level, $color)
  @if $level == 'soft'
    box-shadow: 0px 3px 6px $color
  @else if $level == 'low'
    box-shadow: 6px 0 3px $color
  @else if $level == 'mid'
    box-shadow: 24px 0 8px $color
  @else if $level == 'high'
    box-shadow: 32px 0 16px $color
  @else if $level == 'veryHigh'
    box-shadow: 48px 0 18px $color
  @else if $level == 'none'
    box-shadow: none

@function -compass-space-list($item1, $item2: null, $item3: null, $item4: null, $item5: null, $item6: null, $item7: null, $item8: null, $item9: null)
  // Support for polymorphism.
  @if type-of($item1) == "list"
    // Passing a single array of properties.
    $items: $item1
  @else
    $items: $item1 $item2 $item3 $item4 $item5 $item6 $item7 $item8 $item9
  $full: first-value-of($items)
  @for $i from 2 through length($items)
    $item: nth($items, $i)
    @if $item != null
      $full: $full $item
  @return $full

@if length($query) % 2 != 0
      $loop-to: $loop-to - 1

    $i: 1

    @while $i <= $loop-to
      $media-query: $media-query + "(" + nth($query, $i) + ": " + nth($query, $i + 1) + ") "

      @if $i + 1 != $loop-to
        $media-query: $media-query + "and "

      $i: $i + 2

    @media #{$media-query}
      @content

@function last-index($list, $value, $start-at: -1)
	@if list.length($list) > 0
		$start-at: validate-index.validate-index('last-index', 'start-at', $start-at, $list)

		@if meta.type-of($start-at) != 'number'
			@error $start-at

		@for $index from $start-at through 1
			@if list.nth($list, $index) == $value
				@return $index

	@return 0

=transform-origin($origin-x: $default-origin-x, $origin-y: $default-origin-y, $origin-z: false, $only3d: if($origin-z, true, false))
  $origin: unquote("")
  @if $origin-x or $origin-y or $origin-z
    @if $origin-x
      $origin: $origin-x
    @else
      $origin: 50%
    @if $origin-y
      $origin: $origin $origin-y
    @else
      @if $origin-z
        $origin: $origin 50%
    @if $origin-z
      $origin: $origin $origin-z
    +apply-origin($origin, $only3d)

@function configure($z-config, $base: 0, $path...)
  $-is-ready: true !global

  @if meta.is-list($z-config) or meta.is-string($z-config)
    $z-config: -to-config-($z-config, $base)

  @if list.is-empty($path)
    $z: map.merge($z, $z-config) !global
  @else
    $z: map.set($z, $path..., $z-config) !global
  @return $z

=font-weight($font-weight)
  @if $font-weight == 'extra-bold'
    font-weight: 800
  @if $font-weight == 'bold'
    font-weight: 700
  @else if $font-weight == 'semi-bold'
    font-weight: 600
  @else if $font-weight == 'medium'
    font-weight: 500
  @else if $font-weight == 'regular'
    font-weight: 400
  @else
    font-weight: 400

=font-size($modifier)
  @if $modifier == 'tn'
    font-size: $font-size-tn
  @else if $modifier == 'xs'
    font-size: $font-size-xs
  @else if $modifier == 'sm'
    font-size: $font-size-sm
  @else if $modifier == 'md'
    font-size: $font-size-md
  @else if $modifier == 'lg'
    font-size: $font-size-lg
  @else if $modifier == 'xl'
    font-size: $font-size-xl
  @else if $modifier == 'hg'
    font-size: $font-size-hg

@function color-stops($item1, $item2: null, $item3: null, $item4: null, $item5: null, $item6: null, $item7: null, $item8: null, $item9: null)
  $items: $item2, $item3, $item4, $item5, $item6, $item7, $item8, $item9
  $full: $item1
  @each $item in $items
    @if $item != null
      $full: $full, $item
  @return $full

=text-shadow($level, $color)
  @if $level == 'low'
    text-shadow: 6px 0 3px $color
  @else if $level == 'mid'
    text-shadow: 24px 0 8px $color
  @else if $level == 'high'
    text-shadow: 32px 0 16px $color
  @else if $level == 'veryHigh'
    text-shadow: 48px 0 18px $color
  @else if $level == 'none'
    text-shadow: none

=box-shadow($level, $color)
  @if $level == 'soft'
    box-shadow: 0 3px 6px $color
  @else if $level == 'low'
    box-shadow: 6px 0 3px $color
  @else if $level == 'mid'
    box-shadow: 24px 0 8px $color
  @else if $level == 'high'
    box-shadow: 32px 0 16px $color
  @else if $level == 'veryHigh'
    box-shadow: 48px 0 18px $color
  @else if $level == 'none'
    box-shadow: none

=font-size($modifier)
  @if $modifier == 'tn'
    font-size: var(--font-tn)
  @else if $modifier == 'xs'
    font-size: var(--font-xs)
  @else if $modifier == 'sm'
    font-size: var(--font-sm)
  @else if $modifier == 'md'
    font-size: var(--font-md)
  @else if $modifier == 'lg'
    font-size: var(--font-lg)
  @else if $modifier == 'xl'
    font-size: var(--font-xl)
  @else if $modifier == 'hg'
    font-size: var(--font-hg)

=border-radius($modifier)
  @if $modifier == 'sm'
    border-radius: $small-2
  @else if $modifier == 'md'
    border-radius: $small-4
  @else if $modifier == 'lg'
    border-radius: $medium-2
  @else if $modifier == 'pill'
    border-radius: 500px
  @else if $modifier == 'circular'
    border-radius: 50%
  @else if $modifier == 'none'
    border-radius: 0

=box-shadow($level, $color)
  @if $level == 'low'
    box-shadow: 6px 0 3px $color
  @else if $level == 'mid'
    box-shadow: 24px 0 8px $color
  @else if $level == 'high'
    box-shadow: 32px 0 16px $color
  @else if $level == 'veryHigh'
    box-shadow: 48px 0 18px $color
  @else if $level == 'none'
    box-shadow: none

@function reject($list, $reject1, $reject2: null, $reject3: null, $reject4: null, $reject5: null, $reject6: null, $reject7: null, $reject8: null, $reject9: null)
  $rejects: $reject1, $reject2, $reject3, $reject4, $reject5, $reject6, $reject7, $reject8, $reject9
  $full: false
  @each $item in $list
    @if index($rejects, $item)
    @else
      @if $full
        $full: $full, $item
      @else
        $full: $item
  @return $full

=apply-origin($origin, $only3d)
  $only3d: $only3d or -compass-list-size(-compass-list($origin)) > 2
  @if $only3d
    +experimental(transform-origin, $origin, -moz, -webkit, -o, -ms, not -khtml, official)
  @else
    +experimental(transform-origin, $origin, -moz, -webkit, -o, -ms, not -khtml, official)
